1	// Types
2	
3	export interface Customer {
4	  yearsWithMHPCO: number;
5	}
6	
7	export interface Item {
8	  type: string;
9	  material?: string;
10	  enchantment?: number;
11	  cursed?: boolean;
12	}
13	
14	export interface QuoteStep {
15	  op: 'quote';
16	  items: Item[];
17	}
18	
19	export interface Damage {
20	  itemType: string;
21	  amount: number;
22	}
23	
24	export interface Incident {
25	  cause: string;
26	  damages: Damage[];
27	}
28	
29	export interface ClaimStep {
30	  op: 'claim';
31	  policy: number;
32	  incident: Incident;
33	}
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export interface Scenario {
38	  customer: Customer;
39	  steps: Step[];
40	}
41	
42	export interface QuoteResult {
43	  premium: number;
44	}
45	
46	export interface ClaimResult {
47	  payout: number;
48	  remainingCap: number;
49	}
50	
51	export type StepResult = QuoteResult | ClaimResult;
52	
53	export interface ScenarioOutput {
54	  results: StepResult[];
55	}
56	
57	// Item catalog
58	
59	const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
60	  sword:  { value: 1000, premium: 100 },
61	  amulet: { value: 600,  premium: 60 },
62	  staff:  { value: 800,  premium: 80 },
63	  potion: { value: 400,  premium: 40 },
64	};
65	
66	const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
67	
68	const COMPONENT_VALUE = 250;
69	const COMPONENT_PREMIUM = 25;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	const COMPONENT_BLOCK_SIZE = 3;
72	
73	const PROCESSING_FEE = 5;
74	const DEDUCTIBLE_PER_DAMAGE = 100;
75	
76	function isComponent(type: string): boolean {
77	  return COMPONENT_TYPES.has(type);
78	}
79	
80	function isKnownType(type: string): boolean {
81	  return type in MAIN_ITEMS || isComponent(type);
82	}
83	
84	function itemInsuranceValue(item: Item): number {
85	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].value;
86	  if (isComponent(item.type)) return COMPONENT_VALUE;
87	  throw new Error(`Unknown item type: ${item.type}`);
88	}
89	
90	// Premium calculation
91	
92	interface ItemBase {
93	  item: Item;
94	  basePremium: number;
95	}
96	
97	function itemBasePremiums(items: Item[]): ItemBase[] {
98	  // Main items
99	  const mains: ItemBase[] = [];
100	  // Components grouped by type
101	  const componentsByType: Record<string, Item[]> = {};
102	
103	  for (const item of items) {
104	    if (!isKnownType(item.type)) {
105	      throw new Error(`Unknown item type: ${item.type}`);
106	    }
107	    if (item.type in MAIN_ITEMS) {
108	      mains.push({ item, basePremium: MAIN_ITEMS[item.type].premium });
109	    } else {
110	      if (!componentsByType[item.type]) componentsByType[item.type] = [];
111	      componentsByType[item.type].push(item);
112	    }
113	  }
114	
115	  const componentBases: ItemBase[] = [];
116	  for (const type of Object.keys(componentsByType)) {
117	    const group = componentsByType[type];
118	    const count = group.length;
119	    // Block discount applies only when the count is exactly the block size
120	    let totalGroupBase: number;
121	    if (count === COMPONENT_BLOCK_SIZE) {
122	      totalGroupBase = COMPONENT_BLOCK_PREMIUM;
123	    } else {
124	      totalGroupBase = count * COMPONENT_PREMIUM;
125	    }
126	    const perItem = count === 0 ? 0 : totalGroupBase / count;
127	    for (const it of group) {
128	      componentBases.push({ item: it, basePremium: perItem });
129	    }
130	  }
131	
132	  return [...mains, ...componentBases];
133	}
134	
135	function itemSurcharge(base: ItemBase): number {
136	  let surcharge = 0;
137	  const item = base.item;
138	  if (item.cursed) {
139	    surcharge += base.basePremium * 0.5;
140	  }
141	  if (item.enchantment !== undefined && item.enchantment >= 5) {
142	    surcharge += base.basePremium * 0.3;
143	  }
144	  return surcharge;
145	}
146	
147	function roundUp(n: number): number {
148	  return Math.ceil(n);
149	}
150	
151	function roundDown(n: number): number {
152	  return Math.floor(n);
153	}
154	
155	export function computePremium(items: Item[], customer: Customer, isFollowUpContract: boolean): number {
156	  const bases = itemBasePremiums(items);
157	
158	  const policyBase = bases.reduce((sum, b) => sum + b.basePremium, 0);
159	  const itemSurcharges = bases.reduce((sum, b) => sum + itemSurcharge(b), 0);
160	
161	  // Policy-wide modifiers apply to policy base premium
162	  let policyMods = 0;
163	  if (customer.yearsWithMHPCO >= 2) {
164	    policyMods -= policyBase * 0.2; // loyalty discount
165	  }
166	  // First insurance surcharge: applies per item in quote (each item is a first insurance)
167	  // Per the spec, the surcharge is 10% — but the integration examples show it as a flat
168	  // application against the policy base. Re-reading:
169	  //   "A first insurance carries a 10 % initial assessment surcharge."
170	  //   In the integration example (newcomer cursed sword): 100 base + 50 curse + 10 first
171	  //   insurance = 160. So 10% of 100 (base of that item, "first insurance" per item).
172	  // Each item in the quote is treated as a "first insurance" per the second integration ex.
173	  const firstInsuranceSurcharge = bases.reduce((sum, b) => sum + b.basePremium * 0.1, 0);
174	
175	  // Follow-up contract discount: 15% on each contract after the first
176	  let followUp = 0;
177	  if (isFollowUpContract) {
178	    followUp = -policyBase * 0.15;
179	  }
180	
181	  const beforeFee = policyBase + itemSurcharges + policyMods + firstInsuranceSurcharge + followUp;
182	  const total = beforeFee + PROCESSING_FEE;
183	
184	  return roundUp(total);
185	}
186	
187	// Claim processing
188	
189	interface Policy {
190	  items: Item[];
191	  insuranceSum: number;
192	  cap: number;
193	  remainingCap: number;
194	}
195	
196	export function buildPolicy(items: Item[]): Policy {
197	  // Validate all known
198	  for (const it of items) {
199	    if (!isKnownType(it.type)) throw new Error(`Unknown item type: ${it.type}`);
200	  }
201	  const insuranceSum = items.reduce((sum, it) => sum + itemInsuranceValue(it), 0);
202	  const cap = insuranceSum * 2;
203	  return { items, insuranceSum, cap, remainingCap: cap };
204	}
205	
206	function payoutForDamage(item: Item, amount: number): number {
207	  let reimbursable = amount;
208	  const enchantment = item.enchantment ?? 0;
209	  const isDragon = item.material === 'dragon';
210	  const isHighlyEnchanted = enchantment >= 8;
211	
212	  if (isHighlyEnchanted) {
213	    // High-enchantment 50% rule wins even when material is dragon
214	    reimbursable = amount * 0.5;
215	  } else if (isDragon) {
216	    reimbursable = amount;
217	  } else {
218	    reimbursable = amount;
219	  }
220	  const afterDeductible = reimbursable - DEDUCTIBLE_PER_DAMAGE;
221	  return Math.max(0, afterDeductible);
222	}
223	
224	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
225	  // Validate damages: count of each type cannot exceed policy items of that type
226	  const policyCountsByType: Record<string, number> = {};
227	  for (const it of policy.items) {
228	    policyCountsByType[it.type] = (policyCountsByType[it.type] ?? 0) + 1;
229	  }
230	  const damageCountsByType: Record<string, number> = {};
231	  for (const d of incident.damages) {
232	    if (d.amount < 0) throw new Error(`Negative damage amount: ${d.amount}`);
233	    if (!isKnownType(d.itemType)) throw new Error(`Unknown damage item type: ${d.itemType}`);
234	    damageCountsByType[d.itemType] = (damageCountsByType[d.itemType] ?? 0) + 1;
235	  }
236	  for (const type of Object.keys(damageCountsByType)) {
237	    if ((policyCountsByType[type] ?? 0) < damageCountsByType[type]) {
238	      throw new Error(`Damage references item type not in policy or exceeds count: ${type}`);
239	    }
240	  }
241	
242	  // Match each damage to an available item of that type (first match)
243	  // For simplicity, match in order; if there are multiple items of same type with
244	  // different properties (e.g. dragon-material), match each damage to a distinct item.
245	  const itemsByType: Record<string, Item[]> = {};
246	  for (const it of policy.items) {
247	    if (!itemsByType[it.type]) itemsByType[it.type] = [];
248	    itemsByType[it.type].push(it);
249	  }
250	  // Make working copies (we'll pop as we use them)
251	  const available: Record<string, Item[]> = {};
252	  for (const k of Object.keys(itemsByType)) {
253	    available[k] = [...itemsByType[k]];
254	  }
255	
256	  let total = 0;
257	  for (const d of incident.damages) {
258	    const candidates = available[d.itemType];
259	    if (!candidates || candidates.length === 0) {
260	      throw new Error(`No item available for damage: ${d.itemType}`);
261	    }
262	    const item = candidates.shift()!;
263	    const p = payoutForDamage(item, d.amount);
264	    total += p;
265	  }
266	
267	  // Cap to remainingCap
268	  let payout = total;
269	  if (payout > policy.remainingCap) {
270	    payout = policy.remainingCap;
271	  }
272	  // Round down (in favor of MHPCO)
273	  payout = roundDown(payout);
274	  policy.remainingCap = policy.remainingCap - payout;
275	  if (policy.remainingCap < 0) policy.remainingCap = 0;
276	  return { payout, remainingCap: policy.remainingCap };
277	}
278	
279	// Scenario runner
280	
281	export function runScenario(scenario: Scenario): ScenarioOutput {
282	  const results: StepResult[] = [];
283	  const policies: Record<number, Policy> = {};
284	  let quoteCount = 0;
285	
286	  for (let i = 0; i < scenario.steps.length; i++) {
287	    const step = scenario.steps[i];
288	    if (step.op === 'quote') {
289	      const isFollowUp = quoteCount >= 1;
290	      const premium = computePremium(step.items, scenario.customer, isFollowUp);
291	      // Build policy and store
292	      const policy = buildPolicy(step.items);
293	      policies[i] = policy;
294	      results.push({ premium });
295	      quoteCount++;
296	    } else {
297	      const policy = policies[step.policy];
298	      if (!policy) throw new Error(`No policy at step ${step.policy}`);
299	      const r = processClaim(policy, step.incident);
300	      results.push(r);
301	    }
302	  }
303	  return { results };
304	}
