4	function premiumOf(scenario: Scenario, stepIdx = 0): number {
5	  const out = runScenario(scenario);
6	  const r = out.results[stepIdx] as { premium: number };
7	  return r.premium;
8	}
9	
10	function claimResult(scenario: Scenario, stepIdx: number): { payout: number; remainingCap: number } {
11	  const out = runScenario(scenario);
12	  return out.results[stepIdx] as { payout: number; remainingCap: number };
13	}
