3	async function readStdin(): Promise<string> {
4	  return new Promise((resolve, reject) => {
5	    let data = '';
6	    process.stdin.setEncoding('utf8');
7	    process.stdin.on('data', (chunk) => { data += chunk; });
8	    process.stdin.on('end', () => resolve(data));
9	    process.stdin.on('error', reject);
10	  });
11	}
12	
13	async function main(): Promise<void> {
14	  try {
15	    const input = await readStdin();
16	    const scenario: Scenario = JSON.parse(input);
17	    const output = runScenario(scenario);
18	    process.stdout.write(JSON.stringify(output));
19	  } catch (err) {
20	    const msg = err instanceof Error ? err.message : String(err);
21	    process.stderr.write(`Error: ${msg}\n`);
22	    process.exit(1);
23	  }
24	}
25	
26	main();
