  const isHighlyEnchanted = (item.enchantment ?? 0) >= 8;
  const reimbursable = isHighlyEnchanted ? amount * 0.5 : amount;
  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
