1	// Types
2	
3	export interface Customer {
4	  yearsWithMHPCO: number;
5	}
6	
7	export interface Item {
8	  type: string;
9	  material?: string;
10	  enchantment?: number;
11	  cursed?: boolean;
12	}
13	
14	export interface QuoteStep {
15	  op: 'quote';
16	  items: Item[];
17	}
18	
19	export interface Damage {
20	  itemType: string;
21	  amount: number;
22	}
23	
24	export interface Incident {
25	  cause: string;
26	  damages: Damage[];
27	}
28	
29	export interface ClaimStep {
30	  op: 'claim';
31	  policy: number;
32	  incident: Incident;
33	}
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export interface Scenario {
38	  customer: Customer;
39	  steps: Step[];
40	}
41	
42	export interface QuoteResult {
43	  premium: number;
44	}
45	
46	export interface ClaimResult {
47	  payout: number;
48	  remainingCap: number;
49	}
50	
51	export type StepResult = QuoteResult | ClaimResult;
52	
53	export interface ScenarioOutput {
54	  results: StepResult[];
55	}
56	
57	// Item catalog
58	
59	const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
60	  sword:  { value: 1000, premium: 100 },
61	  amulet: { value: 600,  premium: 60 },
62	  staff:  { value: 800,  premium: 80 },
63	  potion: { value: 400,  premium: 40 },
64	};
65	
66	const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
67	
68	const COMPONENT_VALUE = 250;
69	const COMPONENT_PREMIUM = 25;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	const COMPONENT_BLOCK_SIZE = 3;
72	
73	const PROCESSING_FEE = 5;
74	const DEDUCTIBLE_PER_DAMAGE = 100;
75	
76	function isComponent(type: string): boolean {
77	  return COMPONENT_TYPES.has(type);
78	}
79	
80	function isKnownType(type: string): boolean {
81	  return type in MAIN_ITEMS || isComponent(type);
82	}
83	
84	function itemInsuranceValue(item: Item): number {
85	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].value;
86	  if (isComponent(item.type)) return COMPONENT_VALUE;
87	  throw new Error(`Unknown item type: ${item.type}`);
88	}
89	
90	// Premium calculation
91	
92	interface ItemBase {
93	  item: Item;
94	  basePremium: number;
95	}
96	
97	function itemBasePremiums(items: Item[]): ItemBase[] {
98	  // Main items
99	  const mains: ItemBase[] = [];
100	  // Components grouped by type
101	  const componentsByType: Record<string, Item[]> = {};
102	
103	  for (const item of items) {
104	    if (!isKnownType(item.type)) {
105	      throw new Error(`Unknown item type: ${item.type}`);
106	    }
107	    if (item.type in MAIN_ITEMS) {
108	      mains.push({ item, basePremium: MAIN_ITEMS[item.type].premium });
109	    } else {
110	      if (!componentsByType[item.type]) componentsByType[item.type] = [];
111	      componentsByType[item.type].push(item);
112	    }
113	  }
114	
115	  const componentBases: ItemBase[] = [];
116	  for (const type of Object.keys(componentsByType)) {
117	    const group = componentsByType[type];
118	    const count = group.length;
119	    // Block discount applies only when the count is exactly the block size
120	    let totalGroupBase: number;
121	    if (count === COMPONENT_BLOCK_SIZE) {
122	      totalGroupBase = COMPONENT_BLOCK_PREMIUM;
123	    } else {
124	      totalGroupBase = count * COMPONENT_PREMIUM;
125	    }
126	    const perItem = count === 0 ? 0 : totalGroupBase / count;
127	    for (const it of group) {
128	      componentBases.push({ item: it, basePremium: perItem });
129	    }
130	  }
131	
132	  return [...mains, ...componentBases];
133	}
134	
135	function itemSurcharge(base: ItemBase): number {
136	  let surcharge = 0;
137	  const item = base.item;
138	  if (item.cursed) {
139	    surcharge += base.basePremium * 0.5;
140	  }
141	  if (item.enchantment !== undefined && item.enchantment >= 5) {
142	    surcharge += base.basePremium * 0.3;
143	  }
144	  return surcharge;
145	}
146	
147	function roundUp(n: number): number {
148	  return Math.ceil(n);
149	}
150	
151	function roundDown(n: number): number {
152	  return Math.floor(n);
153	}
154	
155	export function computePremium(items: Item[], customer: Customer, isFollowUpContract: boolean): number {
156	  const bases = itemBasePremiums(items);
157	
158	  const policyBase = bases.reduce((sum, b) => sum + b.basePremium, 0);
159	  const itemSurcharges = bases.reduce((sum, b) => sum + itemSurcharge(b), 0);
160	
161	  // Loyalty discount: 20% off the policy base for customers with >= 2 years.
162	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? -policyBase * 0.2 : 0;
163	
164	  // First-insurance surcharge: 10% applied per item's base premium (each item is a
165	  // first insurance on its first contract).
166	  const firstInsuranceSurcharge = policyBase * 0.1;
167	
168	  // Follow-up contract discount: 15% off the policy base on every contract after the first.
169	  const followUpDiscount = isFollowUpContract ? -policyBase * 0.15 : 0;
170	
171	  const total =
172	    policyBase +
173	    itemSurcharges +
174	    loyaltyDiscount +
175	    firstInsuranceSurcharge +
176	    followUpDiscount +
177	    PROCESSING_FEE;
178	
179	  return roundUp(total);
180	}
181	
182	// Claim processing
183	
184	interface Policy {
185	  items: Item[];
186	  insuranceSum: number;
187	  cap: number;
188	  remainingCap: number;
189	}
190	
191	export function buildPolicy(items: Item[]): Policy {
192	  // Validate all known
193	  for (const it of items) {
194	    if (!isKnownType(it.type)) throw new Error(`Unknown item type: ${it.type}`);
195	  }
196	  const insuranceSum = items.reduce((sum, it) => sum + itemInsuranceValue(it), 0);
197	  const cap = insuranceSum * 2;
198	  return { items, insuranceSum, cap, remainingCap: cap };
199	}
200	
201	function payoutForDamage(item: Item, amount: number): number {
202	  // High-enchantment 50% rule wins even when material is dragon.
203	  // Otherwise (dragon or standard) the full damage amount is reimbursable.
204	  const isHighlyEnchanted = (item.enchantment ?? 0) >= 8;
205	  const reimbursable = isHighlyEnchanted ? amount * 0.5 : amount;
206	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
207	}
208	
209	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
210	  // Validate damages: count of each type cannot exceed policy items of that type
211	  const policyCountsByType: Record<string, number> = {};
212	  for (const it of policy.items) {
213	    policyCountsByType[it.type] = (policyCountsByType[it.type] ?? 0) + 1;
214	  }
215	  const damageCountsByType: Record<string, number> = {};
216	  for (const d of incident.damages) {
217	    if (d.amount < 0) throw new Error(`Negative damage amount: ${d.amount}`);
218	    if (!isKnownType(d.itemType)) throw new Error(`Unknown damage item type: ${d.itemType}`);
219	    damageCountsByType[d.itemType] = (damageCountsByType[d.itemType] ?? 0) + 1;
220	  }
221	  for (const type of Object.keys(damageCountsByType)) {
222	    if ((policyCountsByType[type] ?? 0) < damageCountsByType[type]) {
223	      throw new Error(`Damage references item type not in policy or exceeds count: ${type}`);
224	    }
225	  }
226	
227	  // Match each damage to an available item of that type (first match)
228	  // For simplicity, match in order; if there are multiple items of same type with
229	  // different properties (e.g. dragon-material), match each damage to a distinct item.
230	  const itemsByType: Record<string, Item[]> = {};
231	  for (const it of policy.items) {
232	    if (!itemsByType[it.type]) itemsByType[it.type] = [];
233	    itemsByType[it.type].push(it);
234	  }
235	  // Make working copies (we'll pop as we use them)
236	  const available: Record<string, Item[]> = {};
237	  for (const k of Object.keys(itemsByType)) {
238	    available[k] = [...itemsByType[k]];
239	  }
240	
241	  let total = 0;
242	  for (const d of incident.damages) {
243	    const candidates = available[d.itemType];
244	    if (!candidates || candidates.length === 0) {
245	      throw new Error(`No item available for damage: ${d.itemType}`);
246	    }
247	    const item = candidates.shift()!;
248	    const p = payoutForDamage(item, d.amount);
249	    total += p;
250	  }
251	
252	  // Cap to remainingCap, then round down (in favor of MHPCO).
253	  const payout = roundDown(Math.min(total, policy.remainingCap));
254	  policy.remainingCap -= payout;
255	  return { payout, remainingCap: policy.remainingCap };
256	}
257	
258	// Scenario runner
259	
260	export function runScenario(scenario: Scenario): ScenarioOutput {
261	  const results: StepResult[] = [];
262	  const policies: Record<number, Policy> = {};
263	  let quoteCount = 0;
264	
265	  for (let i = 0; i < scenario.steps.length; i++) {
266	    const step = scenario.steps[i];
267	    if (step.op === 'quote') {
268	      const isFollowUp = quoteCount >= 1;
269	      const premium = computePremium(step.items, scenario.customer, isFollowUp);
270	      // Build policy and store
271	      const policy = buildPolicy(step.items);
272	      policies[i] = policy;
273	      results.push({ premium });
274	      quoteCount++;
275	    } else {
276	      const policy = policies[step.policy];
