function itemBasePremiums(items: Item[]): ItemBase[] {
  // Main items
  const mains: ItemBase[] = [];
  // Components grouped by type
  const componentsByType: Record<string, Item[]> = {};

  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
    if (item.type in MAIN_ITEMS) {
      mains.push({ item, basePremium: MAIN_ITEMS[item.type].premium });
    } else {
      if (!componentsByType[item.type]) componentsByType[item.type] = [];
      componentsByType[item.type].push(item);
    }
  }

  const componentBases: ItemBase[] = [];
  for (const type of Object.keys(componentsByType)) {
    const group = componentsByType[type];
    const count = group.length;
    // Block discount applies only when the count is exactly the block size
    let totalGroupBase: number;
    if (count === COMPONENT_BLOCK_SIZE) {
      totalGroupBase = COMPONENT_BLOCK_PREMIUM;
    } else {
      totalGroupBase = count * COMPONENT_PREMIUM;
    }
    const perItem = count === 0 ? 0 : totalGroupBase / count;
    for (const it of group) {
      componentBases.push({ item: it, basePremium: perItem });
    }
  }

  return [...mains, ...componentBases];
}

