146	export function computePremium(items: Item[], customer: Customer, isFollowUpContract: boolean): number {
147	  const bases = itemBasePremiums(items);
148	
149	  const policyBase = bases.reduce((sum, b) => sum + b.basePremium, 0);
150	  const itemSurcharges = bases.reduce((sum, b) => sum + itemSurcharge(b), 0);
151	
152	  // Loyalty discount: 20% off the policy base for customers with >= 2 years.
153	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? -policyBase * 0.2 : 0;
154	
155	  // First-insurance surcharge: 10% applied per item's base premium (each item is a
156	  // first insurance on its first contract).
157	  const firstInsuranceSurcharge = policyBase * 0.1;
158	
159	  // Follow-up contract discount: 15% off the policy base on every contract after the first.
160	  const followUpDiscount = isFollowUpContract ? -policyBase * 0.15 : 0;
161	
162	  const total =
163	    policyBase +
164	    itemSurcharges +
165	    loyaltyDiscount +
166	    firstInsuranceSurcharge +
167	    followUpDiscount +
168	    PROCESSING_FEE;
169	
170	  return roundUp(total);
171	}
