182	export function buildPolicy(items: Item[]): Policy {
183	  // Validate all known
184	  for (const it of items) {
185	    if (!isKnownType(it.type)) throw new Error(`Unknown item type: ${it.type}`);
186	  }
187	  const insuranceSum = items.reduce((sum, it) => sum + itemInsuranceValue(it), 0);
188	  const cap = insuranceSum * 2;
189	  return { items, insuranceSum, cap, remainingCap: cap };
190	}
