192	function payoutForDamage(item: Item, amount: number): number {
193	  // High-enchantment 50% rule wins even when material is dragon.
194	  // Otherwise (dragon or standard) the full damage amount is reimbursable.
195	  const isHighlyEnchanted = (item.enchantment ?? 0) >= 8;
196	  const reimbursable = isHighlyEnchanted ? amount * 0.5 : amount;
197	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
198	}
