210	  for (const it of policy.items) {
211	    (available[it.type] ??= []).push(it);
212	  }
213	
214	  let total = 0;
215	  for (const d of incident.damages) {
216	    const candidates = available[d.itemType];
217	    if (!candidates || candidates.length === 0) {
218	      throw new Error(`Damage references item type not in policy or exceeds count: ${d.itemType}`);
219	    }
220	    const item = candidates.shift()!;
221	    total += payoutForDamage(item, d.amount);
222	  }
223	
224	  // Cap to remainingCap, then round down (in favor of MHPCO).
225	  const payout = roundDown(Math.min(total, policy.remainingCap));
226	  policy.remainingCap -= payout;
227	  return { payout, remainingCap: policy.remainingCap };
228	}
229	
230	// Scenario runner
231	
232	export function runScenario(scenario: Scenario): ScenarioOutput {
233	  const results: StepResult[] = [];
234	  const policies: Record<number, Policy> = {};
235	  let quoteCount = 0;
236	
237	  for (let i = 0; i < scenario.steps.length; i++) {
238	    const step = scenario.steps[i];
239	    if (step.op === 'quote') {
240	      const isFollowUp = quoteCount >= 1;
241	      const premium = computePremium(step.items, scenario.customer, isFollowUp);
242	      // Build policy and store
243	      const policy = buildPolicy(step.items);
244	      policies[i] = policy;
245	      results.push({ premium });
246	      quoteCount++;
247	    } else {
248	      const policy = policies[step.policy];
249	      if (!policy) throw new Error(`No policy at step ${step.policy}`);
250	      const r = processClaim(policy, step.incident);
251	      results.push(r);
252	    }
253	  }
254	  return { results };
